264		@LogExecution()
265		async waitForTask({
266			taskId,
267			intervalMs = 5000,
268			maxAttempts = 60,
269		}: {
270			taskId: string;
271			intervalMs?: number;
272			maxAttempts?: number;
273		}): Promise<{ state: string; model_id?: string }> {
274			for (let attempt = 1; attempt <= maxAttempts; attempt++) {
275				const task = await this.getTask({ taskId });
276				this.logger.log(
277					`Task ${taskId} — attempt ${attempt}/${maxAttempts}, state: ${task.state}`,
278				);
279	
280				if (task.state === 'COMPLETED') {
281					return task;
282				}
283	
284				if (task.state === 'FAILED') {
285					throw new Error(`Task ${taskId} failed`);
286				}
287	
288				await new Promise((resolve) => setTimeout(resolve, intervalMs));
289			}
290	
291			throw new Error(`Task ${taskId} timed out after ${maxAttempts} attempts`);
292		}
