49		private async resolveModelId(): Promise<void> {
50			try {
51				const modelId = await this.opensearchService.findDeployedModelId({
52					modelGroupName: MODEL_GROUP_NAME,
53				});
54	
55				if (modelId && modelId !== this.modelId) {
56					const previousModelId = this.modelId;
57					this.modelId = modelId;
58					this.logger.log(`Model ID updated: ${previousModelId ?? 'none'} -> ${modelId}`);
59				} else if (!modelId) {
60					this.logger.warn(
61						'No deployed model found. Neural search will not work until bootstrap is run.',
62					);
63				}
64			} catch {
65				this.logger.warn('Failed to resolve model ID. OpenSearch may not be available.');
66			}
67		}
