78		private detectBrand({ text }: { text: string }): string | null {
79			const sorted = [...NEURAL_SEARCH_KNOWN_BRANDS].sort((a, b) => b.length - a.length);
80			for (const brand of sorted) {
81				const escaped = brand.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
82				if (new RegExp(`\\b${escaped}\\b`, 'i').test(text)) {
83					return brand;
84				}
85			}
86			return null;
87		}
