89		private detectColor({ text }: { text: string }): string | null {
90			const sorted = [...NEURAL_SEARCH_KNOWN_COLORS].sort((a, b) => b.length - a.length);
91			for (const color of sorted) {
92				const escaped = color.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
93				if (new RegExp(`\\b${escaped}\\b`, 'i').test(text)) {
94					return color;
95				}
96			}
97			return null;
98		}
