100		private readonly MEASUREMENT_UNITS_PATTERN =
101			/\b\d+\s*(?:oz|ounce|ml|liter|litre|gal|gallon|inch|in|cm|mm|ft|foot|feet)\b/i;
102	
103		private readonly PRICE_RANGE_PATTERNS: {
104			pattern: RegExp;
105			extract: ({
106				match,
107			}: {
108				match: RegExpExecArray;
109			}) => { min: number | null; max: number | null } | null;
110		}[] = [
111			{
112				pattern: /\b(?:under|below|less\s+than|up\s+to)\s+\$(\d+(?:\.\d{1,2})?)/i,
113				extract: ({ match }) => {
114					const max = parseFloat(match[1] ?? '');
115					return isNaN(max) ? null : { min: null, max };
116				},
117			},
118			{
119				pattern: /\bfrom\s+\$(\d+(?:\.\d{1,2})?)\s+to\s+\$(\d+(?:\.\d{1,2})?)/i,
120				extract: ({ match }) => {
121					const min = parseFloat(match[1] ?? '');
122					const max = parseFloat(match[2] ?? '');
123					return isNaN(min) || isNaN(max) ? null : { min, max };
124				},
125			},
126			{
127				pattern: /\$(\d+(?:\.\d{1,2})?)\s*[-–]\s*\$(\d+(?:\.\d{1,2})?)/i,
128				extract: ({ match }) => {
129					const min = parseFloat(match[1] ?? '');
130					const max = parseFloat(match[2] ?? '');
131					return isNaN(min) || isNaN(max) ? null : { min, max };
132				},
133			},
134			{
135				pattern: /\$(\d+(?:\.\d{1,2})?)\s+to\s+\$(\d+(?:\.\d{1,2})?)/i,
136				extract: ({ match }) => {
137					const min = parseFloat(match[1] ?? '');
138					const max = parseFloat(match[2] ?? '');
139					return isNaN(min) || isNaN(max) ? null : { min, max };
140				},
141			},
142			{
143				pattern: /\bto\s+\$(\d+(?:\.\d{1,2})?)/i,
144				extract: ({ match }) => {
145					const max = parseFloat(match[1] ?? '');
146					return isNaN(max) ? null : { min: null, max };
147				},
148			},
149			{
150				pattern: /\b(?:over|above|more\s+than|from)\s+\$(\d+(?:\.\d{1,2})?)/i,
151				extract: ({ match }) => {
152					const min = parseFloat(match[1] ?? '');
153					return isNaN(min) ? null : { min, max: null };
154				},
155			},
156			{
157				pattern: /\b(?:around|about|~)\s*\$(\d+(?:\.\d{1,2})?)/i,
158				extract: ({ match }) => {
159					const price = parseFloat(match[1] ?? '');
160					return isNaN(price)
161						? null
162						: { min: Math.round(price * 0.8), max: Math.round(price * 1.2) };
163				},
164			},
165			{
166				pattern: /\$(\d+(?:\.\d{1,2})?)/,
167				extract: ({ match }) => {
168					const price = parseFloat(match[1] ?? '');
169					return isNaN(price)
170						? null
171						: { min: Math.round(price * 0.8), max: Math.round(price * 1.2) };
172				},
173			},
174		];
