176		private detectPriceRange({
177			text,
178		}: {
179			text: string;
180		}): { min: number | null; max: number | null } | null {
181			for (const { pattern, extract } of this.PRICE_RANGE_PATTERNS) {
182				const match = pattern.exec(text);
183				if (match) {
184					return extract({ match });
185				}
186			}
187			return null;
188		}
