190		private stripContractions({ text }: { text: string }): string {
191			let result = text;
192			for (const contraction of NEURAL_SEARCH_CONTRACTIONS) {
193				result = result.replace(new RegExp(`\\b${contraction}\\b`, 'gi'), '');
194			}
195			return result;
196		}
