198		private readonly PRICE_STRIP_PATTERN =
199			/\b(?:under|below|less\s+than|up\s+to|over|above|more\s+than|from|around|about|~)?\s*\$\d+(?:\.\d{1,2})?\s*(?:[-–]\s*\$\d+(?:\.\d{1,2})?)?\b/gi;
