201		private detectSize({ text }: { text: string }): string | null {
202			const cleanedText = this.stripContractions({
203				text: text
204					.replace(this.MEASUREMENT_UNITS_PATTERN, '')
205					.replace(this.PRICE_STRIP_PATTERN, ''),
206			});
207			const sorted = [...NEURAL_SEARCH_KNOWN_SIZES].sort((a, b) => b.length - a.length);
208			for (const size of sorted) {
209				const escaped = size.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
210				if (new RegExp(`\\b${escaped}\\b`, 'i').test(cleanedText)) {
211					return size;
212				}
213			}
214			return null;
215		}
