422		@LogExecution({
423			paramFormatter: (
424				params: [{ queryText: string; size: number; categoryFilter?: string }],
425			) => ({
426				queryText: params[0].queryText,
427				size: params[0].size,
428				categoryFilter: params[0].categoryFilter,
429			}),
430			responseFormatter: (response: IOpensearchProduct[]) => ({
431				totalResults: response.length,
432			}),
