434		async searchProducts({
435			queryText,
436			size = NEURAL_SEARCH_LIMIT,
437			categoryFilter,
438		}: {
439			queryText: string;
440			size?: number;
441			categoryFilter?: string;
442		}): Promise<IOpensearchProduct[]> {
443			const sanitizedQuery = this.sanitizeQuery({ text: queryText });
444			const normalizedQuery = this.normalizeQuery({ text: sanitizedQuery });
445			const genderProductTypes = this.detectGenderProductTypes({ text: sanitizedQuery });
446			const priceLevels = this.detectPriceLevels({ text: sanitizedQuery });
447			const brand = this.detectBrand({ text: sanitizedQuery });
448			const detectedColor = this.detectColor({ text: sanitizedQuery });
449			const detectedSize = this.detectSize({ text: sanitizedQuery });
450			const detectedPriceRange = this.detectPriceRange({ text: queryText });
451	
452			const baseFilters: object[] = [
453				{ term: { status: 'active' } },
454				...(categoryFilter
455					? [
456							{
457								bool: {
458									should: [
459										{ term: { broad_category_names: categoryFilter } },
460										{ term: { sub_category_names: categoryFilter } },
461									],
462									minimum_should_match: 1,
463								},
464							},
465						]
466					: []),
467			];
468	
469			const genderBoosts: object[] = genderProductTypes
470				? [{ terms: { product_type: genderProductTypes } }]
471				: [];
472	
473			const priceBoosts: object[] =
474				priceLevels?.map((level) => ({
475					term: { price_level: { value: level } },
476				})) ?? [];
477	
478			const brandBoosts: object[] = brand ? [{ terms: { brand: [brand] } }] : [];
479	
480			const colorBoosts: object[] = detectedColor
481				? [
482						{
483							nested: {
484								path: 'colors',
485								query: {
486									wildcard: {
487										'colors.name': {
488											value: `*${detectedColor.toLowerCase()}*`,
489											case_insensitive: true,
490										},
491									},
492								},
493							},
494						},
495					]
496				: [];
497	
498			const unitPriceBoosts: object[] = detectedPriceRange
499				? [
500						{
501							range: {
502								price: {
503									...(detectedPriceRange.min !== null && { gte: detectedPriceRange.min }),
504									...(detectedPriceRange.max !== null && { lte: detectedPriceRange.max }),
505								},
506							},
507						},
508					]
509				: [];
510	
511			const sizeBoosts: object[] = detectedSize
512				? [
513						{
514							wildcard: {
515								sizes: { value: `*${detectedSize.toLowerCase()}*`, case_insensitive: true },
516							},
517						},
518					]
519				: [];
520	
521			const hits = await this.opensearchService.search({
522				indexName: this.indexName,
523				searchPipeline: 'hybrid-search-pipeline',
524				body: {
525					size,
526					min_score: 0.4,
527					query: {
528						hybrid: {
529							queries: [
530								{
531									bool: {
532										should: [
533											{ match: { name: { query: normalizedQuery, boost: 0.1 } } },
534											{
535												match: {
536													condensed_features: { query: normalizedQuery, boost: 0.3 },
537												},
538											},
539											...priceBoosts,
540											...brandBoosts,
541											...genderBoosts,
542											...colorBoosts,
543											...sizeBoosts,
544											...unitPriceBoosts,
545										],
546										filter: baseFilters,
547									},
548								},
549								{
550									neural: {
551										product_embedding: {
552											query_text: normalizedQuery,
553											model_id: this.getModelId(),
554											k: size * 5,
555											filter: { bool: { filter: baseFilters } },
556										},
557									},
558								},
559							],
560						},
561					},
562					collapse: { field: 'product_id' },
563					_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
564				},
565			});
566	
567			const maxScore = Math.max(...hits.map((hit) => hit._score), 1);
568	
569			return hits.map((hit) => {
570				const product = hit._source as IOpensearchProduct;
571				const imageUrl = detectedColor
572					? this.resolveColorImageUrl({ product, colorName: detectedColor })
573					: null;
574				const normalizedScore = hit._score / maxScore;
575	
576				return {
577					...product,
578					_id: hit._id,
579					confidenceScore: Math.min(Math.round(Math.pow(normalizedScore, 2) * 100), 100),
580					...(imageUrl !== null && { style_card_image_url: imageUrl }),
581				};
582			});
583		}
584	
585		@LogExecution({
586			paramFormatter: (
587				params: [{ categories: Record<string, string>[]; size?: number }],
588			) => ({
589				categories: params[0].categories.map((c) => Object.keys(c)[0]),
590				size: params[0].size,
591			}),
592			responseFormatter: (response: IOpensearchProduct[]) => ({
593				total: response.length,
594			}),
595		})
596		async searchProductsByCategories({
597			categories,
598			size,
599		}: {
600			categories: Record<string, string>[];
601			size?: number;
602		}): Promise<IOpensearchProduct[]> {
603			const effectiveSize = size ?? NEURAL_SEARCH_LIMIT;
604			const perCategory = Math.ceil(effectiveSize / categories.length);
605	
606			const categoryResults = await Promise.all(
607				categories.map((categoryEntry) => {
608					const categoryName = Object.keys(categoryEntry)[0] ?? '';
609					const categoryQueryText = Object.values(categoryEntry)[0] ?? '';
610	
611					return this.searchProducts({
612						queryText: categoryQueryText || categoryName,
613						size: perCategory,
614						categoryFilter: categoryName,
615					});
616				}),
617			);
618	
619			const interleaved: IOpensearchProduct[] = [];
620			const maxLen = Math.max(...categoryResults.map((r) => r.length));
621			for (let i = 0; i < maxLen; i++) {
622				for (const results of categoryResults) {
623					const item = results[i];
624					if (item !== undefined) {
625						interleaved.push(item);
626					}
627				}
628			}
629	
630			return interleaved.slice(0, effectiveSize);
631		}
