1	import { Logger } from '@nestjs/common';
2	import { Command, CommandRunner, Option } from 'nest-commander';
3	
4	import { OpensearchService } from '@modules/opensearch/opensearch.service';
5	
6	import { CronJobExecution } from '@decorators/cron-job-execution.decorator';
7	
8	const MODEL_NAME = 'huggingface/sentence-transformers/all-distilroberta-v1';
9	const MODEL_VERSION = '1.0.1';
10	const MODEL_GROUP_NAME = 'neural-search-model-group';
11	const INGEST_PIPELINE_ID = 'products-neural-pipeline';
12	const SEARCH_PIPELINE_ID = 'hybrid-search-pipeline';
13	
14	interface SetupNeuralSearchOptions {
15		modelFormat?: string;
16		skipClusterSettings?: boolean;
17		skipModelSetup?: boolean;
18		skipPipelines?: boolean;
19	}
20	
21	@Command({
22		name: 'setup-neural-search',
23		description:
24			'Bootstrap ML pipeline for neural search: register model, deploy, create pipelines',
25	})
26	export class SetupNeuralSearchCommand extends CommandRunner {
27		private readonly logger = new Logger(SetupNeuralSearchCommand.name);
28	
29		constructor(private readonly opensearchService: OpensearchService) {
30			super();
31		}
32	
33		@CronJobExecution({ jobName: 'setup-neural-search' })
34		async run(_passedParams: string[], options: SetupNeuralSearchOptions): Promise<void> {
35			const modelFormat = options.modelFormat ?? 'TORCH_SCRIPT';
36			const skipClusterSettings = options.skipClusterSettings ?? false;
37			const skipModelSetup = options.skipModelSetup ?? false;
38			const skipPipelines = options.skipPipelines ?? false;
39	
40			try {
41				if (!skipClusterSettings) {
42					this.logger.log('Step 1: Configuring cluster ML settings...');
43					await this.opensearchService.configureClusterMLSettings();
44				}
45	
46				let modelId: string | undefined;
47	
48				if (!skipModelSetup) {
49					this.logger.log('Step 2: Registering model group...');
50					const modelGroupId = await this.opensearchService.registerModelGroup({
51						name: MODEL_GROUP_NAME,
52						description: 'Model group for neural search embeddings',
53					});
54	
55					this.logger.log('Step 3: Registering model...');
56					const registerTaskId = await this.opensearchService.registerModel({
57						name: MODEL_NAME,
58						version: MODEL_VERSION,
59						modelGroupId,
60						modelFormat,
61					});
62	
63					this.logger.log('Step 4: Waiting for model registration...');
64					const registerResult = await this.opensearchService.waitForTask({
65						taskId: registerTaskId,
66					});
67					modelId = registerResult.model_id;
68	
69					if (!modelId) {
70						throw new Error('Model registration completed but no model_id returned');
71					}
72	
73					this.logger.log(`Model registered: ${modelId}`);
74	
75					this.logger.log('Step 5: Deploying model...');
76					const deployTaskId = await this.opensearchService.deployModel({ modelId });
77	
78					this.logger.log('Step 6: Waiting for model deployment...');
79					await this.opensearchService.waitForTask({ taskId: deployTaskId });
80					this.logger.log('Model deployed successfully');
81				}
82	
83				if (!skipPipelines) {
84					modelId ??=
85						(await this.opensearchService.findDeployedModelId({
86							modelGroupName: MODEL_GROUP_NAME,
87						})) ?? undefined;
88	
89					if (!modelId) {
90						this.logger.error(
91							'Cannot create pipelines without model_id. Run without --skip-model-setup first.',
92						);
93						process.exit(1);
94					}
95	
96					this.logger.log('Step 7: Creating ingest pipeline...');
97					await this.opensearchService.createIngestPipeline({
98						pipelineId: INGEST_PIPELINE_ID,
99						modelId,
100						sourceField: 'combined_text_for_embedding',
101						targetField: 'product_embedding',
102					});
103	
104					this.logger.log('Step 8: Creating search pipeline...');
105					await this.opensearchService.createSearchPipeline({
106						pipelineId: SEARCH_PIPELINE_ID,
107						normalizationTechnique: 'min_max',
108						combinationTechnique: 'arithmetic_mean',
109						weights: [0.2, 0.8],
110					});
111				}
112	
113				this.logger.log('Neural search setup completed successfully');
114	
115				if (modelId) {
116					this.logger.log(`Model ID: ${modelId} (resolved dynamically at app startup)`);
117				}
118			} catch (error) {
119				this.logger.error(`Setup failed: ${(error as Error).message}`);
120				process.exit(1);
121			}
122		}
123	
124		@Option({
125			flags: '-f, --model-format <modelFormat>',
126			description: 'Model format: TORCH_SCRIPT or ONNX (default: TORCH_SCRIPT)',
127		})
128		parseModelFormat(value: string): string {
129			const valid = ['TORCH_SCRIPT', 'ONNX'];
130			if (!valid.includes(value)) {
131				throw new Error(`Model format must be one of: ${valid.join(', ')}`);
132			}
133			return value;
134		}
135	
136		@Option({
137			flags: '--skip-cluster-settings',
138			description: 'Skip configuring cluster ML settings',
139		})
140		parseSkipClusterSettings(): boolean {
141			return true;
142		}
143	
144		@Option({
145			flags: '--skip-model-setup',
146			description: 'Skip model registration and deployment',
147		})
148		parseSkipModelSetup(): boolean {
149			return true;
150		}
151	
152		@Option({
153			flags: '--skip-pipelines',
154			description: 'Skip creating ingest and search pipelines',
155		})
156		parseSkipPipelines(): boolean {
157			return true;
158		}
159	}
