76				});
77	
78				const retrievedValue = await this.cacheService.get<string>({
79					namespace: Namespaces.HEALTH_CHECK,
80					key: testKey,
81				});
82	
83				if (retrievedValue !== testValue) {
84					throw new Error('Redis data integrity check failed');
85				}
86	
87				const latency = Date.now() - start;
88	
89				return this.healthIndicatorService.check('redis').up({
90					message: 'Redis is working',
