1	import { Client } from '@opensearch-project/opensearch';
2	
3	import { getEnv } from '@utils/get-env-variable.util';
4	
5	import {
6		OPENSEARCH_HOST,
7		OPENSEARCH_PASSWORD,
8		OPENSEARCH_USERNAME,
9	} from '@constants/env-variables.constant';
10	
11	const TEST_INDEX_PREFIXES = ['e2e_test_', 'e2e-test-', 'e2e-', 'e2e_', 'test_', 'test-'];
12	const TEST_RESOURCE_PREFIXES = ['e2e-', 'e2e_', 'test-', 'test_'];
13	
14	async function resetTestOpensearch(): Promise<void> {
15		console.log('🗑️  Resetting test OpenSearch...');
16	
17		const nodeEnv = process.env['NODE_ENV'] ?? 'development';
18		if (nodeEnv === 'production') {
19			console.error('❌ Cannot reset OpenSearch in production environment!');
20			process.exit(1);
21		}
22	
23		const host = getEnv<string>({ key: OPENSEARCH_HOST });
24		const username = getEnv<string>({ key: OPENSEARCH_USERNAME });
25		const password = getEnv<string>({ key: OPENSEARCH_PASSWORD });
26	
27		if (
28			!host.includes('localhost') &&
29			!host.includes('127.0.0.1') &&
30			!host.includes('test')
31		) {
32			console.error('❌ OpenSearch host does not appear to be a test environment!');
33			console.error(`   Host: ${host}`);
34			console.error('   Only localhost, 127.0.0.1, or hosts containing "test" are allowed');
35			process.exit(1);
36		}
37	
38		console.log(`📡 Connecting to OpenSearch at ${host}...`);
39	
40		const client = new Client({
41			node: host,
42			auth: { username, password },
43			ssl: { rejectUnauthorized: false },
44		});
45	
46		try {
47			await client.cluster.health();
48			console.log('✅ Connected to OpenSearch');
49		} catch (error: unknown) {
50			const err = error instanceof Error ? error : new Error(String(error));
51			console.error('❌ Failed to connect to OpenSearch:', err.message);
52			process.exit(1);
53		}
54	
55		console.log('🗂️  Cleaning test indices...');
56		await cleanupTestIndices({ client });
57	
58		console.log('🧪 Cleaning test model groups...');
59		await cleanupTestModelGroups({ client });
60	
61		console.log('🔧 Cleaning test pipelines...');
62		await cleanupTestPipelines({ client });
63	
64		console.log('🎉 Test OpenSearch reset complete!');
65	}
66	
67	async function cleanupTestIndices({ client }: { client: Client }): Promise<void> {
68		try {
69			const response = await client.cat.indices({ format: 'json' });
70			const indices = response.body as { index: string; 'docs.count': string }[];
71	
72			const testIndices = indices.filter((idx) =>
73				TEST_INDEX_PREFIXES.some((prefix) => idx.index.startsWith(prefix)),
74			);
75	
76			if (testIndices.length === 0) {
77				console.log('  ℹ️  No test indices to clean');
78				return;
79			}
80	
81			console.log(`  🗑️  Found ${testIndices.length} test indices to delete`);
82	
83			for (const idx of testIndices) {
84				try {
85					await client.indices.delete({ index: idx.index });
86					console.log(`    ✓ Deleted index: ${idx.index} (${idx['docs.count']} docs)`);
87				} catch (error: unknown) {
88					const err = error instanceof Error ? error : new Error(String(error));
89					console.log(`    ✗ Failed to delete ${idx.index}: ${err.message}`);
90				}
91			}
92	
93			console.log(`  ✅ Cleaned ${testIndices.length} test indices`);
94		} catch (error: unknown) {
95			const err = error instanceof Error ? error : new Error(String(error));
96			console.error('  ❌ Error cleaning test indices:', err.message);
97		}
98	}
99	
100	async function cleanupTestModelGroups({ client }: { client: Client }): Promise<void> {
101		try {
102			const response = await client.transport.request({
103				method: 'POST',
104				path: '/_plugins/_ml/model_groups/_search',
105				body: {
106					query: {
107						bool: {
108							should: TEST_RESOURCE_PREFIXES.map((prefix) => ({
109								prefix: { 'name.keyword': prefix },
110							})),
111						},
112					},
113					size: 100,
114				},
115			});
116	
117			const hits = (
118				response.body as { hits: { hits: { _id: string; _source: { name: string } }[] } }
119			).hits.hits;
120	
121			if (hits.length === 0) {
122				console.log('  ℹ️  No test model groups to clean');
123				return;
124			}
125	
126			console.log(`  🗑️  Found ${hits.length} test model groups to delete`);
127	
128			for (const hit of hits) {
129				try {
130					const modelsResponse = await client.transport.request({
131						method: 'POST',
132						path: '/_plugins/_ml/models/_search',
133						body: {
134							query: { term: { model_group_id: hit._id } },
