231							method: 'DELETE',
232							path: `/_search/pipeline/${pipelineId}`,
233						});
234						console.log(`    ✓ Deleted search pipeline: ${pipelineId}`);
235					} catch (error: unknown) {
236						const err = error instanceof Error ? error : new Error(String(error));
237						console.log(
238							`    ✗ Failed to delete search pipeline ${pipelineId}: ${err.message}`,
239						);
240					}
241				}
242			} else {
243				console.log('  ℹ️  No test search pipelines to clean');
244			}
245	
246			console.log('  ✅ Cleaned test pipelines');
247		} catch (error: unknown) {
248			const err = error instanceof Error ? error : new Error(String(error));
